"""# 1. Single Agent Training

## 1.1. The Coin Game Environment

We represent the game state as a `chex` dataclass — a lightweight, JAX-compatible
structure. The environment exposes two functions:
- `reset(key)` — initializes a new episode and returns the first observation
- `step(key, state, actions)` — advances the environment by one timestep

### Observation space
The observation for the agent is a **flattened 4-channel grid** of shape `(grid_size × grid_size × 4,)`.
Each channel is a binary indicator for a different entity (1 on the considered position, and 0 on the rest):
- Channel 0: agent position
- Channel 1: empty (reserved for a second agent — useful when extending to multi-agent)
- Channel 2: red coin position
- Channel 3: blue coin position

### Action space
5 discrete actions: right, left, down, up, stay.
"""

@chex.dataclass
class EnvState:
    pos:        jnp.ndarray   # (2,) — agent's [row, col] position on the grid
    coin_r:     jnp.ndarray   # (2,) — red coin's [row, col] position
    coin_b:     jnp.ndarray   # (2,) — blue coin's [row, col] position
    step_count: int           # current timestep within the episode

# Movement deltas for each action in [row, col] format.
MOVES = jnp.array([
    [ 0,  1],   # right
    [ 0, -1],   # left
    [-1,  0],   # down
    [ 1,  0],   # up
    [ 0,  0],   # stay
])

class CoinGame:
    """
    A minimal, JAX-compatible single-agent Coin Game.

    The agent collects red and blue coins, both worth +1 reward.
    Collected coins immediately respawn at a random empty cell.
    """

    def __init__(self, grid_size: int = 4, episode_length: int = 10):
        self.grid_size     = grid_size
        self.episode_length = episode_length
        self.agents        = ["agent_0"]
        self.obs_dim        = grid_size * grid_size * 4 # flattened observation size
        self.n_actions     = 5

    # ── Observations ─────────────────────────────────────────────────────────
    @functools.partial(jit, static_argnums=(0,))
    def _state_to_obs(self, state: EnvState):
        """
        Converts an EnvState into a dict of observations, one per agent.
        Each observation is a flattened binary grid with 4 channels.
        For each channel, a 1.0 is set on the considered position, and 0.0s on the rest.
        Channel 1 is left empty (zeros) — it would hold a second agent's position
        in a multi-agent version of this environment.
        """
        g = self.grid_size
        grid = jnp.zeros((g, g, 4), dtype=jnp.float32)
        grid = grid.at[state.pos[0], state.pos[1], 0].set(1.0) # agent position
        # Channel 1 intentionally left as zeros (placeholder for agent_1)
        grid = grid.at[state.coin_r[0], state.coin_r[1], 2].set(1.0) # red coin
        grid = grid.at[state.coin_b[0], state.coin_b[1], 3].set(1.0) # blue coin
        return {"agent_0": grid.flatten()}

    # ── Reset ────────────────────────────────────────────────────────────────
    @functools.partial(jit, static_argnums=(0,))
    def reset(self, key: jnp.ndarray) -> Tuple[dict, EnvState]:
        """
        Starts a new episode. Samples 3 non-overlapping positions (without
        replacement from the flattened grid) for the agent and both coins.
        Returns the initial observation dict and the initial EnvState.
        """
        flat_idx = jax.random.choice(key, self.grid_size**2, shape=(3,), replace=False)
        #                                  ↑ 16 possible values     ↑ choose 3   ↑ no replacement
        def to_2d(idx): return jnp.array([idx // self.grid_size, idx % self.grid_size])
        #                                     ↑ row is the quotient     ↑ column is the remainder
        state = EnvState(
            pos = to_2d(flat_idx[0]),
            coin_r = to_2d(flat_idx[1]),
            coin_b = to_2d(flat_idx[2]),
            step_count = 0,
        )
        return self._state_to_obs(state), state

    # ── Step ─────────────────────────────────────────────────────────────────
    @functools.partial(jit, static_argnums=(0,))
    def step(self, key: jnp.ndarray, state: EnvState, actions: dict):
        """
        Advances the environment by one timestep.

        1. Move the agent according to `actions["agent_0"]`, wrapping at boundaries
           (toroidal grid: the agent exits one side and enters the other).
        2. Check whether the agent's new position coincides with either coin.
        3. Reward = +1 for each coin collected (both coins are equally valuable).
        4. Respawn any collected coin at a random empty cell, ensuring the two
           coins never share the same cell.
        5. Return the next observation, next state, reward dict, and done flag.
        """
        a0 = actions["agent_0"]
        # Wrap-around movement: the grid is toroidal (0,1,...,grid_size-1 and grid_size=0)
        new_pos = (state.pos + MOVES[a0]) % self.grid_size

        gets_r = jnp.all(new_pos == state.coin_r)
        gets_b = jnp.all(new_pos == state.coin_b)

        # Both coins are worth +1; the agent has no reason to prefer one over the other
        reward = (gets_r * 1.0) + (gets_b * 1.0)

        # Respawn collected coins, ensuring they don't overlap the other existing coin
        k1, k2 = jax.random.split(key)
        G = self.grid_size
        def respawn(keep_coin, rand_key):
            flat_keep = keep_coin[0] * G + keep_coin[1]   # 2D → 1D
            valid = jnp.ones(G*G).at[flat_keep].set(0.0)  # vector with 1.0s on the allowed cells and 0.0s on the blocked ones
            new_flat = jax.random.choice(rand_key, G*G, p=valid/valid.sum()) # → uniform probability over allowed cells
            return jnp.array([new_flat // G, new_flat % G])

        new_coin_r = jnp.where(gets_r, respawn(state.coin_b, k1), state.coin_r)
        #                                       ↑ value if gets_r==True     ↑ value if gets_r==False
        new_coin_b = jnp.where(gets_b, respawn(new_coin_r, k2), state.coin_b)
        #                                       ↑ do not overlap with new/old red coin

        new_step = state.step_count + 1
        next_state = EnvState(pos=new_pos, coin_r=new_coin_r, coin_b=new_coin_b, step_count=new_step)

        return self._state_to_obs(next_state), next_state, {"agent_0": reward}, new_step >= self.episode_length

# Quick sanity check
env = CoinGame(grid_size=4, episode_length=16)
key = jax.random.PRNGKey(0)
obs, state = env.reset(key)
print('obs shape:', obs['agent_0'].shape)
obs, state, rewards, done = env.step(key, state, {'agent_0': 0})
print('rewards:', rewards, '| done:', done)

"""---
## 1.2. Policy Network

The policy is a small MLP that maps an observation to **logits over actions**.
This parameterizes the stochastic policy $\pi_\theta(a \mid s)$:

$$\pi_\theta(a \mid s) = \text{softmax}(\text{MLP}_\theta(s))_a$$

We use `equinox` (a JAX-native neural network library) to define the network.

Architecture: Linear(obs_dim → 64) → Tanh → Linear(64 → 64) → Tanh → Linear(64 → n_actions)
"""

class Policy(eqx.Module):
    """Two-layer MLP that outputs action logits given an observation."""
    linear1: eqx.nn.Linear
    linear2: eqx.nn.Linear
    linear3: eqx.nn.Linear

    def __init__(self, obs_dim: int, n_actions: int, key):
        k1, k2, k3 = jax.random.split(key, 3)
        self.linear1 = eqx.nn.Linear(obs_dim,   64, key=k1)
        self.linear2 = eqx.nn.Linear(64,        64, key=k2)
        self.linear3 = eqx.nn.Linear(64, n_actions, key=k3)

    def __call__(self, obs):
        x = obs.astype(jnp.float32)
        x = jax.nn.tanh(self.linear1(x))
        x = jax.nn.tanh(self.linear2(x))
        x = self.linear3(x)
        return x

@eqx.filter_jit
def sample_action(policy, obs, key):
    """
    Samples an action from the policy's distribution π(·|obs).

    Steps:
    1. Forward pass → logits
    2. Convert to log-probabilities via log_softmax
    3. Sample a categorical action proportional to exp(logits)
    4. Return the action, its log-probability log π(a|s), and its probability π(a|s)

    The log-probability is what REINFORCE needs to compute gradients.
    """
    logits   = policy(obs)
    action   = jax.random.categorical(key, logits)
    #                     ↑ argmax will always choose the maximum (deterministic)
    #                       during TRAINING we want to balance exploration/exploitation
    #                       during TEST we will use argmax for exploitation (greedy)
    log_probs = jax.nn.log_softmax(logits)
    log_prob = log_probs[action]
    probs = jnp.exp(log_probs)
    prob = probs[action]
    return action, log_prob, prob

# Test
p = Policy(env.obs_dim, env.n_actions, jax.random.PRNGKey(42))
a, lp, p = sample_action(p, obs['agent_0'], jax.random.PRNGKey(1))
print('action:', int(a), '| log_prob:', float(lp), '| prob:', float(p))

"""## 1.3. REINFORCE Algorithm

REINFORCE (Williams, 1992) is the simplest policy gradient algorithm.
The core idea:
> *"If an action led to high return, increase its probability. If it led to low return, decrease it."*

The policy gradient theorem gives us:

$$\nabla_\theta J(\theta) = \mathbb{E}_{\tau \sim \pi_\theta}\left[\sum_t G_t \cdot \nabla_\theta \log \pi_\theta(a_t \mid s_t)\right]$$

where $G_t = \sum_{k \geq t} \gamma^{k-t} r_k$ is the **discounted return from step $t$** —
the total (discounted) reward the agent actually received from that point onwards.

### Three steps per episode:
1. **Collect a trajectory**: run the policy and record $(s_t, a_t, r_t)$ for each step $t$
2. **Compute discounted returns** $G_t$ for each step
3. **Gradient step**: minimize $\mathcal{L} = -\sum_t G_t \log\pi_\theta(a_t \mid s_t)$

Note the **minus sign**: we minimize the loss, which is equivalent to maximizing the expected return.

### Why normalize the returns?
We subtract the mean and divide by the standard deviation of $\{G_t\}$ before the update.
This reduces variance and stabilizes training without changing which actions are relatively
better or worse within the episode.
"""

def discounted_returns(rewards: list, gamma: float) -> jnp.ndarray:
    """
    Computes the discounted return G_t for each timestep t in the episode.

    G_t = r_t + γ·r_{t+1} + γ²·r_{t+2} + ...

    We accumulate backwards (from the last step to the first) for efficiency.
    The result is normalized (zero mean, unit variance) across the episode
    to reduce gradient variance during training.
    """
    R, returns = 0.0, []
    for r in reversed(rewards):
        R = float(r) + gamma * R
        returns.insert(0, R)
    G = jnp.array(returns)
    # Normalize for stable gradients
    return (G - G.mean()) / (G.std() + 1e-8)


@jit
def reinforce_loss(policy, obs_batch, actions_batch, returns):
    """
    Computes the REINFORCE loss for one episode.

    L = -mean_t [ G_t * log π_θ(a_t | s_t) ]

    Steps:
    1. Run the policy on all observations simultaneously using vmap
       (vectorized map — equivalent to a for-loop over the batch, but fast)
    2. Compute log π(a | s) for every action in the alphabet via log_softmax
    3. Index out the log-prob of the action that was actually taken at each step
    4. Weight each log-prob by its return G_t and negate (we minimize, not maximize)
    """
    # vmap applies `policy` independently to each row of obs_batch
    logits         = jax.vmap(policy)(obs_batch)
    log_probs_all  = jax.nn.log_softmax(logits)   # shape: (T, n_actions)
    # Select the log-prob of the action taken at each step t
    log_probs      = log_probs_all[jnp.arange(len(actions_batch)), actions_batch]  # shape: (T,)
    return -jnp.mean(log_probs * returns)


print('REINFORCE ready.')

"""---
## 1.4. Training Configuration

These are the key hyperparameters. Experiment with them after the first run!

- **EPISODE_LENGTH**: longer episodes give more signal per update but also more variance.
- **GAMMA**: discount factor. Values close to 1 make the agent care about distant rewards.
- **LR**: learning rate for Adam. Too high → unstable; too low → slow convergence.

"""

CONFIG = {
    # Environment
    'GRID_SIZE':       4,
    'EPISODE_LENGTH':  100,   # steps per episode

    # Training
    'NUM_EPISODES':    1800,
    'GAMMA':           0.9,   # discount factor: how much future rewards are discounted
    'LR':              3e-3,  # Adam learning rate

    # Logging
    'SHOW_EVERY':      50,    # print a summary every N episodes
}

"""---
## 1.5. Training Loop

The main loop follows the standard REINFORCE recipe for each episode:

1. Reset the environment to get an initial observation
2. **Rollout**: repeatedly sample actions from the policy and step the environment,
   storing observations, actions, and rewards
3. **Returns**: compute discounted returns G_t from the collected rewards
4. **Update**: take one gradient step to minimize the REINFORCE loss

We also track how many red and blue coins were collected each episode separately,
which lets us verify the agent is actively picking up both coin types.
"""

@eqx.filter_jit
def update_agent(policy, opt_state, optimizer, obs_batch, actions_batch, returns):
    """
    Performs one gradient update step for a single agent.

    `eqx.filter_jit` JIT-compiles the function, but only differentiates through
    the JAX arrays inside `policy` (the network weights), not the static Python
    structure. This is the standard equinox pattern for training.

    Returns the updated policy, optimizer state, and the scalar loss value.
    """
    # Compute loss value AND its gradient w.r.t. policy weights (w) in one pass.
    # `grads` has the exact same structure as `policy`, but each array holds ∂loss/∂w instead of the weight value itself.
    loss, grads = jax.value_and_grad(reinforce_loss)(policy, obs_batch, actions_batch, returns)

    # Ask the optimizer to transform raw gradients into actual parameter updates.
    # We get back both the updates and the new optimizer state.
    updates, new_opt_state = optimizer.update(grads, opt_state)

    # Apply updates: new_weights = old_weights + updates, across every layer at once.
    # Returns a NEW Policy object
    new_policy = optax.apply_updates(policy, updates)
    return new_policy, new_opt_state, loss

def train(config):
    env = CoinGame(config['GRID_SIZE'], config['EPISODE_LENGTH'])

    # One policy + optimizer per agent
    policies, opt_states, optimizers = {}, {}, {}
    for i, agent in enumerate(env.agents):
        pol = Policy(env.obs_dim, env.n_actions, jax.random.PRNGKey(i+42))
        opt = optax.adam(config['LR'])
        policies[agent]   = pol
        optimizers[agent] = opt
        opt_states[agent] = opt.init(eqx.filter(pol, eqx.is_array))

    # History stores one tuple per episode: (episode, total_reward, red_coins, blue_coins)
    history = []
    key = jax.random.PRNGKey(42)

    for ep in range(config['NUM_EPISODES']):
        key, ep_key = jax.random.split(key)
        obs, state = env.reset(ep_key)

        traj = {ag: {'obs': [], 'actions': [], 'rewards': []} for ag in env.agents}

        # Initialize coin counters for this episode
        ep_red_coins = 0
        ep_blue_coins = 0

        # ── Rollout ──────────────────────────────────────────────────────
        done = False
        while not done:
            key, *ks = jax.random.split(key, len(env.agents) + 1)
            actions = {}
            for i, agent in enumerate(env.agents):
                action, _, _ = sample_action(policies[agent], obs[agent], ks[i])
                actions[agent] = action

                traj[agent]['obs'].append(obs[agent])
                traj[agent]['actions'].append(action)

            # Snapshot coin positions BEFORE the step so we can detect collections
            # (after the step, collected coins have already respawned elsewhere)
            old_coin_r = state.coin_r
            old_coin_b = state.coin_b

            key, step_key = jax.random.split(key)
            obs, next_state, rewards, done = env.step(step_key, state, actions)

            # A coin was collected if the agent's new position equals the coin's OLD position
            agent_pos = next_state.pos
            ep_red_coins += int(jnp.all(agent_pos == old_coin_r))
            ep_blue_coins += int(jnp.all(agent_pos == old_coin_b))

            # Advance the state
            state = next_state

            for agent in env.agents:
                traj[agent]['rewards'].append(float(rewards[agent]))

        # ── Update each agent ─────────────────────────────────────────────
        for agent in env.agents:
            obs_b = jnp.stack(traj[agent]['obs'])
            actions_b = jnp.array(traj[agent]['actions'])
            returns = discounted_returns(traj[agent]['rewards'], config['GAMMA'])

            policies[agent], opt_states[agent], _ = update_agent(
                policies[agent], opt_states[agent], optimizers[agent], obs_b, actions_b, returns
            )

        ep_r = {ag: float(sum(v['rewards'])) for ag, v in traj.items()}

        # Save reward AND coin counts
        history.append((ep, ep_r['agent_0'], ep_red_coins, ep_blue_coins))

        if ep % config['SHOW_EVERY'] == 0:
            print(f"Ep {ep:4d}  |  r_0={ep_r['agent_0']:+.1f}  |  Red Coins Picked: {ep_red_coins}  |  Blue Coins Picked: {ep_blue_coins}")

    # ── Save Results ─────────────────────────────────────────────────────────
    timestamp = datetime.now().strftime("%Y-%m-%d_%H-%M-%S")
    save_path = os.path.join(config.get("SAVE_DIR", "./runs"), f"run_{timestamp}")
    os.makedirs(save_path, exist_ok=True)

    # 1. Save the training history to a CSV (with new headers)
    csv_path = os.path.join(save_path, "stats.csv")
    with open(csv_path, "w", newline="") as f:
        writer = csv.writer(f)
        writer.writerow(["episode", "reward_agent_0", "red_coins", "blue_coins"])
        writer.writerows(history)

    # 2. Save the trained policies using pickle
    models_path = os.path.join(save_path, "models.pkl")
    with open(models_path, "wb") as f:
        pickle.dump(policies, f)

    print(f"\nDone! Results and models saved to: {save_path}")
    return policies, history, save_path

policies, history, latest_save_path = train(CONFIG)

"""---
## 1.6. Results — Reward Curves

**What to look for:**
- An untrained (random) agent collects ~10 coins per 100-step episode by chance alone
- A well-trained agent should collect significantly more — around 25–35+
- Both coin colors should increase at a similar rate (the agent has no reason to prefer one)
- Reward ≈ red_coins + blue_coins, so the total reward line should track their sum
"""

def plot_rewards(history, window=50):
    # Unpack the 4-element tuples from history
    eps = np.array([h[0] for h in history])
    r0  = np.array([h[1] for h in history])
    red_coins = np.array([h[2] for h in history])
    blue_coins = np.array([h[3] for h in history])

    def smooth(x):
        return np.convolve(x, np.ones(window)/window, mode='valid')

    BG = '#0f0f12'
    fig, ax = plt.subplots(figsize=(11, 4))
    fig.patch.set_facecolor(BG)
    ax.set_facecolor(BG)

    # 1. Plot Total Reward (White)
    ax.plot(eps, r0, color='#ffffff', alpha=0.15, linewidth=0.7)
    ax.plot(eps[:len(smooth(r0))], smooth(r0), color='#ffffff', linewidth=2.5, label='Total Reward')

    # 2. Plot Red Coins (Red)
    ax.plot(eps, red_coins, color='#ff4545', alpha=0.15, linewidth=0.7)
    ax.plot(eps[:len(smooth(red_coins))], smooth(red_coins), color='#ff4545', linewidth=2.0, label='Red Coins Picked')

    # 3. Plot Blue Coins (Blue)
    ax.plot(eps, blue_coins, color='#80b3ff', alpha=0.15, linewidth=0.7)
    ax.plot(eps[:len(smooth(blue_coins))], smooth(blue_coins), color='#80b3ff', linewidth=2.0, label='Blue Coins Picked')

    ax.axhline(0, color='#444', linestyle='--', linewidth=0.9)
    ax.set_xlabel('Episode', color='#ccc', fontsize=11)
    ax.set_ylabel('Count / Reward', color='#ccc', fontsize=11)
    ax.set_title('Single Agent Pretraining: Coins Collected vs Total Reward', color='white', fontsize=14, fontweight='bold', pad=14)
    ax.tick_params(colors='#777')

    for spine in ax.spines.values():
        spine.set_edgecolor('#333')

    ax.legend(facecolor='#1e1e24', edgecolor='#444', labelcolor='white', fontsize=10, loc='upper left')
    plt.tight_layout()
    plt.show()

plot_rewards(history)

"""---
## 1.7. Visualize a Trained Episode

We load the saved policy from disk and run one episode:
at each step the agent picks `argmax` over the logits.

**How to read the animation:**
- 🔺 Triangle = the agent, with a fading motion trail showing recent positions
- ⬤ Filled circles = coins (red and blue)
- Right panel: cumulative coin counts and total reward so far
"""

def run_episode(save_path, config, seed=42):
    """
    Loads the trained policy from disk and runs one full episode.
    Returns all intermediate states, per-step rewards, and per-step coin collection flags.
    """
    models_file_path = os.path.join(save_path, "models.pkl")
    with open(models_file_path, "rb") as f:
        policies = pickle.load(f)

    env = CoinGame(config['GRID_SIZE'], config['EPISODE_LENGTH'])
    key = jax.random.PRNGKey(seed)
    obs, state = env.reset(key)

    frames  = [state]
    rewards = {'agent_0': []}
    coins   = {'red': [], 'blue': []}
    done = False

    while not done:
        old_rc, old_bc = state.coin_r, state.coin_b
        actions = {"agent_0": int(jnp.argmax(policies["agent_0"](obs["agent_0"])))}
        key, sk = jax.random.split(key)

        obs, state, rws, done = env.step(sk, state, actions)

        frames.append(state)
        rewards['agent_0'].append(float(rws['agent_0']))

        # Track which coin was picked
        coins['red'].append(int(jnp.all(state.pos == old_rc)))
        coins['blue'].append(int(jnp.all(state.pos == old_bc)))

    return frames, rewards, coins

def animate_episode(save_path, config, seed=42, interval_ms=520):
    """
    Produces an interactive HTML animation of one episode.

    Left panel: the grid with the agent (triangle) and coins (circles).
    Right panel: bar chart of total red/blue coins collected and cumulative reward.
    """
    frames, rewards, coins = run_episode(save_path, config, seed)
    G = config['GRID_SIZE']
    T = len(frames) - 1

    BG        = '#13131a'
    GRID_C    = '#2a2a3a'
    RED_AG    = '#ff4545'
    RED_COIN  = '#ff8080'
    BLUE_COIN = '#80b3ff'

    fig = plt.figure(figsize=(12, 5.5), facecolor=BG)
    gs  = fig.add_gridspec(1, 2, width_ratios=[1.25, 0.75], wspace=0.12)

    # ── Grid panel ────────────────────────────────────────────────────────
    ax = fig.add_subplot(gs[0])
    ax.set_facecolor(BG)
    ax.set_xlim(-0.5, G - 0.5); ax.set_ylim(-0.5, G - 0.5)
    ax.set_aspect('equal'); ax.invert_yaxis(); ax.set_xticks([]); ax.set_yticks([])
    for spine in ax.spines.values(): spine.set_edgecolor('#333')

    for r in range(G):
        for c in range(G):
            col = '#1a1a24' if (r+c)%2==0 else '#16161f'
            ax.add_patch(plt.Rectangle((c-.5, r-.5), 1, 1, color=col, zorder=0))
        ax.axhline(r - 0.5, color=GRID_C, lw=1, zorder=1)
        ax.axvline(r - 0.5, color=GRID_C, lw=1, zorder=1)
    ax.axhline(G - 0.5, color=GRID_C, lw=1, zorder=1)
    ax.axvline(G - 0.5, color=GRID_C, lw=1, zorder=1)

    rc_patch = plt.Circle((0,0), 0.28, color=RED_COIN, alpha=0.92, zorder=3)
    bc_patch = plt.Circle((0,0), 0.28, color=BLUE_COIN, alpha=0.92, zorder=3)
    ax.add_patch(rc_patch); ax.add_patch(bc_patch)

    rc_lbl = ax.text(0, 0, '$', ha='center', va='center', fontsize=11, color='white', fontweight='bold', zorder=4)
    bc_lbl = ax.text(0, 0, '$', ha='center', va='center', fontsize=11, color='white', fontweight='bold', zorder=4)

    ra_pt, = ax.plot([], [], '^', ms=22, color=RED_AG, zorder=5, markeredgecolor='white', markeredgewidth=1.2)
    TRAIL = 4
    r_trails = [ax.plot([], [], '-', color=RED_AG, alpha=0.13*(i+1), lw=2.5, zorder=2)[0] for i in range(TRAIL)]

    step_lbl = ax.text(0.03, 0.97, '', transform=ax.transAxes, color='#aaa', fontsize=10, va='top', fontfamily='monospace')
    ax.set_title('Trained agent — greedy policy', color='white', fontsize=12, pad=10)

    legend_elems = [
        mpatches.Patch(color=RED_AG,    label='Agent 0'),
        mpatches.Patch(color=RED_COIN,  label='Red coin'),
        mpatches.Patch(color=BLUE_COIN, label='Blue coin'),
    ]
    ax.legend(handles=legend_elems, loc='lower right', facecolor='#1e1e2a', edgecolor='#333', labelcolor='white', fontsize=8.5)

    # ── Coin Bars & Reward panel ──────────────────────────────────────────
    ax2 = fig.add_subplot(gs[1])
    ax2.set_facecolor(BG)
    ax2.set_title('Coins Collected', color='white', fontsize=11, pad=10)
    ax2.set_xlim(-0.5, 1.5)
    ax2.set_xticks([0, 1])
    ax2.set_xticklabels(['Red Coins', 'Blue Coins'], color='white', fontsize=11)
    ax2.set_ylim(0, config['EPISODE_LENGTH'])
    ax2.axhline(0, color='#444', lw=0.9)
    ax2.tick_params(axis='y', colors='#666')
    ax2.tick_params(axis='x', colors='white')
    for spine in ax2.spines.values(): spine.set_edgecolor('#333')

    # Draw two bars for the two coin types
    bar_rc = ax2.bar([0], [0], color=RED_COIN, alpha=0.9, width=0.5)[0]
    bar_bc = ax2.bar([1], [0], color=BLUE_COIN, alpha=0.9, width=0.5)[0]

    # Absolute reward as text
    rew_text = ax2.text(0.5, 0.9, 'Reward: +0.0', ha='center', va='center',
                        transform=ax2.transAxes, color='white', fontsize=14, fontweight='bold')

    state_box = {'cum_r': 0., 'red_c': 0, 'blue_c': 0, 'rh': []}

    def update(fi):
        if fi == 0:
            state_box['cum_r'] = 0.
            state_box['red_c'] = 0
            state_box['blue_c'] = 0
            state_box['rh'].clear()

        st = frames[fi]
        rc, bc, rp = st.coin_r, st.coin_b, st.pos

        rc_patch.center = (float(rc[1]), float(rc[0])); rc_lbl.set_position((float(rc[1]), float(rc[0])))
        bc_patch.center = (float(bc[1]), float(bc[0])); bc_lbl.set_position((float(bc[1]), float(bc[0])))

        ra_pt.set_data([float(rp[1])], [float(rp[0])])
        state_box['rh'].append((float(rp[1]), float(rp[0])))
        rh = state_box['rh']

        for i, trl in enumerate(r_trails):
            seg = rh[max(0, len(rh)-TRAIL+i): len(rh)-TRAIL+i+2]
            trl.set_data([s[0] for s in seg], [s[1] for s in seg]) if len(seg)>=2 else None

        step_lbl.set_text(f'step {fi} / {T}')

        if fi > 0:
            state_box['cum_r'] += rewards['agent_0'][fi-1]
            state_box['red_c'] += coins['red'][fi-1]
            state_box['blue_c'] += coins['blue'][fi-1]

        # Update visualizations
        bar_rc.set_height(state_box['red_c'])
        bar_bc.set_height(state_box['blue_c'])
        rew_text.set_text(f"Total Reward: {state_box['cum_r']:+.1f}")

        return (rc_patch, bc_patch, ra_pt, *r_trails, step_lbl, bar_rc, bar_bc, rew_text)

    anim = FuncAnimation(fig, update, frames=len(frames), interval=interval_ms, blit=True, repeat=True)
    plt.tight_layout()
    return HTML(anim.to_jshtml())

animate_episode(latest_save_path, CONFIG)

"""# Exercise: Extend to Two Agents

You have a working single-agent setup. Your task is to extend it to a **two-agent cooperative Coin Game** where both agents try to collect coins at the same time. The core idea is that, in this new environment, agents are given points (+1) ONLY for collecting their own coins, while they are penalized (-1) for collecting the other's coins.

This is a genuine multi-agent reinforcement learning (MARL) problem.

### What changes in the environment?

The `EnvState` currently holds one agent position (`pos`). You will need to add a
second position (`pos_1`, or make `pos` a `(2, 2)` array). The observation for each
agent should include:
- Its own position (channel 0)
- The **other** agent's position (channel 1 — currently always zero!)
- The red coin (channel 2)
- The blue coin (channel 3)

The `step` function needs to move **both** agents simultaneously and check whether
**either** one lands on a coin.

> ⚠️ Think carefully about what happens if both agents step onto the same coin at
> the same time. Who gets the reward? Does the coin respawn once or twice?

### What changes in training?

Not much — and that's the beauty of independent learning. Each agent has its own
policy and its own optimizer. The training loop already loops over `env.agents`,
so adding `"agent_1"` to that list is most of the work.

This approach is called **Independent REINFORCE** (or **IL** in general). Each agent
treats the other as part of the environment and ignores the fact that the other
agent is also learning. It's not optimal, but it often works surprisingly well.
"""